            $employee = Employee::firstOrCreate(
                ['name' => trim($row['name'])],
                ['position' => 'Staff']
            );

            foreach ($row['schedule_ids'] as $schedId) {
                $exists = DB::table('schedule_employees')
                    ->where('emp_id', $employee->id)
                    ->where('schedule_id', $schedId)
                    ->exists();
                if (!$exists) {
                    DB::table('schedule_employees')->insert([
                        'emp_id'      => $employee->id,
                        'schedule_id' => $schedId,
                    ]);
                }
            }

            DB::table('checks')->insert([
                'emp_id'          => $employee->id,
                'attendance_time' => $row['time_in'],
                'leave_time'      => $row['time_out'],
                'created_at'      => now(),
                'updated_at'      => now(),
            ]);

            $icon = $row['shift'] === 'MALAM' ? '🌙' : '☀️ ';
            $this->command->info("$icon {$row['shift']} | {$row['hari']} | {$row['name']} | {$row['date']}");
